$XFER_PY -c "
import torch

bf16 = torch.load\('$OUTPUT_DIR/bf16_gold.pt', weights_only=True\)
fp8 = torch.load\('$OUTPUT_DIR/native_fp8.pt', weights_only=True\)

def rrmse\(a, b\):
    a_f, b_f = a.float\(\).flatten\(\), b.float\(\).flatten\(\)
    return \(\(a_f - b_f\).pow\(2\).mean\(\).sqrt\(\) / b_f.pow\(2\).mean\(\).sqrt\(\).clamp\(min=1e-12\)\).item\(\)

def cosine\(a, b\):
    a_f, b_f = a.float\(\).flatten\(\), b.float\(\).flatten\(\)
    return \(a_f @ b_f / \(a_f.norm\(\) * b_f.norm\(\)\).clamp\(min=1e-12\)\).item\(\)

def corr\(a, b\):
    a_f, b_f = a.float\(\).flatten\(\), b.float\(\).flatten\(\)
    a_c, b_c = a_f - a_f.mean\(\), b_f - b_f.mean\(\)
    return \(a_c @ b_c / \(a_c.norm\(\) * b_c.norm\(\)\).clamp\(min=1e-12\)\).item\(\)

def max_rel\(a, b\):
    diff = \(a.float\(\) - b.float\(\)\).abs\(\)
    ref = b.float\(\).abs\(\).clamp\(min=1e-12\)
    return \(diff / ref\).max\(\).item\(\)

print\('='*110\)
print\(f'{\\"Variable\\":<25} {\\"Shape\\":<25} {\\"BF16 norm\\":>10} {\\"FP8 norm\\":>10} {\\"RRMSE\\":>10} {\\"Cosine\\":>10} {\\"Corr\\":>10} {\\"MaxRelErr\\":>10}'\)
print\('='*110\)
for key in ['out', 'dx', 'aux', 'd_router.weight', 'd_c_fc.weight', 'd_c_proj.weight']:
    if key in bf16 and key in fp8:
        g, n = bf16[key], fp8[key]
        shape_str = 'x'.join\(str\(s\) for s in g.shape\)
        print\(f'{key:<25} {shape_str:<25} {g.float\(\).norm\(\):>10.4f} {n.float\(\).norm\(\):>10.4f} {rrmse\(n,g\):>10.6f} {cosine\(n,g\):>10.8f} {corr\(n,g\):>10.8f} {max_rel\(n,g\):>10.4f}'\)
print\(\)

# Check if any variable has concerning precision
RRMSE_THRESHOLD = 0.10  # 10%
issues = []
for key in ['out', 'dx', 'd_c_fc.weight', 'd_c_proj.weight', 'd_router.weight']:
    if key in bf16 and key in fp8:
        r = rrmse\(fp8[key], bf16[key]\)
        c = cosine\(fp8[key], bf16[key]\)
        if r > RRMSE_THRESHOLD:
            issues.append\(f'{key}: RRMSE={r:.4f} > {RRMSE_THRESHOLD}'\)
        if c < 0.99:
            issues.append\(f'{key}: cosine={c:.6f} < 0.99'\)

if issues:
    print\('PRECISION ISSUES:'\)
    for i in issues:
        print\(f'  ! {i}'\)
else:
    print\('ALL VARIABLES PASS PRECISION CHECK \(RRMSE<10%, cosine>0.99\)'\)
" 2>&1 | tee "$OUTPUT_DIR/precision_report.log")

